const msg = $input.first().json.message.toLowerCase();

let intent = "explorando";

if (
  msg.includes("preço") ||
  msg.includes("valor") ||
  msg.includes("comprar") ||
  msg.includes("pagamento") ||
  msg.includes("parcelar")
) {
  intent = "compra";
}

if (
  msg.includes("erro") ||
  msg.includes("não liga") ||
  msg.includes("problema") ||
  msg.includes("defeito") ||
  msg.includes("suporte")
) {
  intent = "suporte_tecnico";
}

return { intent };

const stage = $input.first().json.stage;

return {
  lead_stage: stage,
  updated: true
};
